using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;public class ConsentServiceTests_GetAccessRequestsByPatient_WithSeedPatient_ShouldReturnResult : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {    "AuthService",    "ConsentService"    };    [SkippableFact]    public async Task GetAccessRequestsByPatient_WithSeedPatient_ShouldReturnResult()    {    await AuthenticateAsAdminAsync(ConsentClient);    var response = await GetWithRetryAsync(ConsentClient, $"{ApiEndpoints.AccessRequests.ByPatient(TestSeedData.PatientUserId)}?page=1&pageSize=10");        Assert.Equal(HttpStatusCode.OK, response.StatusCode);    var json = await ReadJsonResponseAsync(response);    Assert.True(json.TryGetProperty("data", out _) || json.TryGetProperty("items", out _) || json.ValueKind == JsonValueKind.Array);    }}
